+    #[test]
+    fn xadd_maxlen_minid_combo_rejected_with_upstream_wording() {
+        let mut store = Store::new();
+        let reply = dispatch_argv(
+            &[
+                b"XADD".to_vec(),
+                b"s".to_vec(),
+                b"MAXLEN".to_vec(),
+                b"10".to_vec(),
+                b"MINID".to_vec(),
+                b"1-0".to_vec(),
+                b"*".to_vec(),
+                b"k".to_vec(),
+                b"v".to_vec(),
+            ],
+            &mut store,
+            0,
+        )
+        .expect("xadd combo");
+        assert_eq!(
+            reply,
+            RespFrame::Error(
+                "ERR syntax error, MAXLEN and MINID options at the same time are not compatible"
+                    .to_string()
+            )
+        );
+    }
+
+    #[test]
+    fn xadd_limit_requires_trim_strategy_and_approx() {
+        let mut store = Store::new();
+        // LIMIT without MAXLEN/MINID
+        let reply = dispatch_argv(
+            &[
+                b"XADD".to_vec(),
+                b"s".to_vec(),
+                b"LIMIT".to_vec(),
+                b"5".to_vec(),
+                b"*".to_vec(),
+                b"k".to_vec(),
+                b"v".to_vec(),
+            ],
+            &mut store,
+            0,
+        )
+        .expect("xadd limit only");
+        assert_eq!(
+            reply,
+            RespFrame::Error(
+                "ERR syntax error, LIMIT cannot be used without specifying a trimming strategy"
+                    .to_string()
+            )
+        );
+
+        // LIMIT with exact (=) MAXLEN — must reject
+        let reply = dispatch_argv(
+            &[
+                b"XADD".to_vec(),
+                b"s".to_vec(),
+                b"MAXLEN".to_vec(),
+                b"=".to_vec(),
+                b"10".to_vec(),
+                b"LIMIT".to_vec(),
+                b"5".to_vec(),
+                b"*".to_vec(),
+                b"k".to_vec(),
+                b"v".to_vec(),
+            ],
+            &mut store,
+            0,
+        )
+        .expect("xadd limit exact");
+        assert_eq!(
+            reply,
+            RespFrame::Error(
+                "ERR syntax error, LIMIT cannot be used without the special ~ option".to_string()
+            )
+        );
+
+        // LIMIT with approx (~) MAXLEN — accepted
+        let reply = dispatch_argv(
+            &[
+                b"XADD".to_vec(),
+                b"s".to_vec(),
+                b"MAXLEN".to_vec(),
+                b"~".to_vec(),
+                b"10".to_vec(),
+                b"LIMIT".to_vec(),
+                b"5".to_vec(),
+                b"1-0".to_vec(),
+                b"k".to_vec(),
+                b"v".to_vec(),
+            ],
+            &mut store,
+            0,
+        )
+        .expect("xadd limit approx");
+        assert_eq!(reply, RespFrame::BulkString(Some(b"1-0".to_vec())));
+
+        // LIMIT negative — must reject
+        let reply = dispatch_argv(
+            &[
+                b"XADD".to_vec(),
+                b"s2".to_vec(),
+                b"MAXLEN".to_vec(),
+                b"~".to_vec(),
+                b"10".to_vec(),
+                b"LIMIT".to_vec(),
+                b"-1".to_vec(),
+                b"1-0".to_vec(),
+                b"k".to_vec(),
+                b"v".to_vec(),
+            ],
+            &mut store,
+            0,
+        )
+        .expect("xadd limit negative");
+        assert_eq!(
+            reply,
+            RespFrame::Error("ERR The LIMIT argument must be >= 0.".to_string())
+        );
+    }
